import {
  MarkdownView,
  Notice,
  Platform,
  Plugin,
  TFile,
  WorkspaceLeaf,
} from "obsidian";
import {
  createDailyNote,
  getAllDailyNotes,
  getDateFromFile,
  getDailyNote,
} from "obsidian-daily-notes-interface";

import { getMoment, type MomentLike } from "./moment";
import { ConfirmationModal } from "./modal";
import { ToolkitRenderer } from "./renderer";
import { getNextSyncDelayMs } from "./scheduler";
import {
  ThingsToolkitReviewView,
  VIEW_TYPE_THINGS_TOOLKIT_REVIEW,
} from "./reviewView";
import {
  DEFAULT_SETTINGS,
  IDailyLogbookReview,
  IDailyLogbookStat,
  ISettings,
  ThingsToolkitSettingsTab,
} from "./settings";
import {
  buildTasksFromSQLRecords,
  fetchThingsToolkit,
  ITask,
} from "./things";
import {
  countThingsTasksInSection,
  groupBy,
  isMacOS,
  updateSection,
} from "./textUtils";

type DailyNoteDate = Parameters<typeof getDailyNote>[0];

function isTFile(file: unknown): file is TFile {
  return file instanceof TFile;
}

function toDailyNoteDate(date: MomentLike): DailyNoteDate {
  return date as unknown as DailyNoteDate;
}

function getDateKey(date: MomentLike): string {
  return date.format("YYYY-MM-DD");
}

export interface ISyncStatus {
  isSyncing: boolean;
  message: string;
}

export default class ThingsToolkitPlugin extends Plugin {
  public options!: ISettings;
  public syncStatus: ISyncStatus = {
    isSyncing: false,
    message: "",
  };

  private syncTimeoutId?: number;
  private lastSyncAttemptTime = 0;
  private settingsTab?: ThingsToolkitSettingsTab;
  private selectedReviewDate = "";
  private statusBarEl?: HTMLElement;

  async onload(): Promise<void> {
    this.scheduleNextSync = this.scheduleNextSync.bind(this);
    this.syncLogbook = this.syncLogbook.bind(this);
    this.tryToScheduleSync = this.tryToScheduleSync.bind(this);
    this.tryToSyncLogbook = this.tryToSyncLogbook.bind(this);

    await this.loadOptions();
    this.selectedReviewDate = getMoment()().format("YYYY-MM-DD");

    this.registerView(
      VIEW_TYPE_THINGS_TOOLKIT_REVIEW,
      (leaf: WorkspaceLeaf) => new ThingsToolkitReviewView(leaf, this)
    );

    this.addCommand({
      id: "sync",
      name: "Sync",
      callback: () => {
        window.setTimeout(() => {
          void this.tryToSyncLogbook();
        }, 20);
      },
    });

    this.addCommand({
      id: "open-review",
      name: "Open review",
      callback: () => {
        void this.activateReviewView();
      },
    });

    this.addRibbonIcon("calendar-check", "Open Things toolkit review", () => {
      void this.activateReviewView();
    });

    this.statusBarEl = this.addStatusBarItem();
    this.statusBarEl.addClass("things-toolkit-status");
    this.statusBarEl.addEventListener("click", () => {
      void this.activateReviewView();
    });

    this.updateStatusBar();

    this.registerEvent(
      this.app.workspace.on("file-open", (file: TFile | null) => {
        this.selectReviewDateFromFile(file);
      })
    );

    this.app.workspace.onLayoutReady(() => {
      this.selectReviewDateFromFile(this.app.workspace.getActiveFile());
    });

    if (this.isSyncSupported()) {
      this.app.workspace.onLayoutReady(() => {
        void this.refreshRecentDailyStats().then(() => {
          this.updateStatusBar();
          this.refreshReviewViews();
        });
      });
    }

    this.settingsTab = new ThingsToolkitSettingsTab(this.app, this);
    this.addSettingTab(this.settingsTab);

    if (
      this.isSyncSupported() &&
      this.options.hasAcceptedDisclaimer &&
      this.options.isSyncEnabled
    ) {
      this.app.workspace.onLayoutReady(() => {
        this.scheduleNextSync();
      });
    }
  }

  isSyncSupported(): boolean {
    return Platform.isDesktopApp && isMacOS();
  }

  getSelectedReviewDate(): string {
    return this.selectedReviewDate;
  }

  async selectReviewDate(
    dateKey: string,
    options: { openDailyNote?: boolean } = {}
  ): Promise<void> {
    this.selectedReviewDate = dateKey;
    this.refreshReviewViews();

    if (options.openDailyNote) {
      await this.openDailyNote(dateKey);
    }
  }

  private selectReviewDateFromFile(file: TFile | null): void {
    const dateKey = this.getDailyNoteDateKey(file);

    if (!dateKey || dateKey === this.selectedReviewDate) {
      return;
    }

    this.selectedReviewDate = dateKey;
    this.refreshReviewViews();
  }

  private getDailyNoteDateKey(file: TFile | null): string | null {
    if (!file) {
      return null;
    }

    return getDateFromFile(file, "day")?.format("YYYY-MM-DD") ?? null;
  }

  async activateReviewView(): Promise<void> {
    let leaf: WorkspaceLeaf | null | undefined = this.app.workspace.getLeavesOfType(
      VIEW_TYPE_THINGS_TOOLKIT_REVIEW
    )[0];

    if (!leaf) {
      leaf = this.app.workspace.getRightLeaf(false);

      if (!leaf) {
        return;
      }

      await leaf.setViewState({
        type: VIEW_TYPE_THINGS_TOOLKIT_REVIEW,
        active: true,
      });
    }

    await this.app.workspace.revealLeaf(leaf);
  }

  async tryToSyncLogbook(): Promise<void> {
    if (!this.isSyncSupported()) {
      new Notice("Things Toolkit sync is only available on macOS desktop.");
      return;
    }

    if (this.options.hasAcceptedDisclaimer) {
      await this.syncLogbook();
      return;
    }

    new ConfirmationModal(this.app, {
      cta: "Sync",
      onAccept: async () => {
        await this.writeOptions({ hasAcceptedDisclaimer: true });
        await this.syncLogbook();
      },
      text:
        "Enabling sync will repair the configured review window from Things3 into Obsidian. This can create or modify many daily notes. Make sure to test the plugin in a test vault before continuing.",
      title: "Sync Now?",
    }).open();
  }

  tryToScheduleSync(): void {
    if (!this.isSyncSupported()) {
      this.cancelScheduledSync();
      return;
    }

    if (this.options.hasAcceptedDisclaimer) {
      this.scheduleNextSync();
      return;
    }

    new ConfirmationModal(this.app, {
      cta: "Sync",
      onAccept: async () => {
        await this.writeOptions({ hasAcceptedDisclaimer: true });
        this.scheduleNextSync();
      },
      onCancel: () => {
        void this.writeOptions({ isSyncEnabled: false }).then(() => {
          this.settingsTab?.display();
        });
      },
      text:
        "Enabling sync will repair the configured review window from Things3 into Obsidian. This can create or modify many daily notes. Make sure to test the plugin in a test vault before continuing.",
      title: "Sync Now?",
    }).open();
  }

  async syncLogbook(): Promise<void> {
    const moment = getMoment();

    if (!this.isSyncSupported()) {
      new Notice("Things Toolkit sync is only available on macOS desktop.");
      return;
    }

    if (this.syncStatus.isSyncing) {
      new Notice("Things Toolkit sync already running");
      return;
    }

    this.lastSyncAttemptTime = moment().unix();
    this.syncStatus = {
      isSyncing: true,
      message: "Syncing...",
    };
    this.settingsTab?.display();

    const logbookRenderer = new ToolkitRenderer(this.app, this.options);
    const dailyNotes = getAllDailyNotes();
    const latestSyncTime = this.options.latestSyncTime || 0;

    try {
      const fetchResult = await fetchThingsToolkit(
        latestSyncTime,
        this.options.appleScriptFallbackLookbackDays,
        this.options.thingsAccessMode,
        this.getReviewWindowDayCount()
      );

      const tasks: ITask[] = buildTasksFromSQLRecords(
        fetchResult.taskRecords,
        fetchResult.checklistRecords
      );
      const taskCount = tasks.length;

      const daysToTasks: Record<string, ITask[]> = groupBy(
        tasks.filter((task) => task.stopDate),
        (task) => moment.unix(task.stopDate).startOf("day").format()
      );

      const dayEntries = Object.entries(daysToTasks).sort(([a], [b]) =>
        moment(a).diff(moment(b))
      );
      const dayCount = dayEntries.length;
      let changedDayCount = 0;

      const dailyStats = this.buildDailyStats(
        dayEntries,
        fetchResult.source,
        moment().unix()
      );

      for (const [dateStr, groupedTasks] of dayEntries) {
        const date = moment(dateStr);
        let dailyNote = getDailyNote(toDailyNoteDate(date), dailyNotes);

        if (!dailyNote) {
          dailyNote = await createDailyNote(toDailyNoteDate(date));
        }

        if (!isTFile(dailyNote)) {
          continue;
        }

        const didChange = await updateSection(
          this.app,
          dailyNote,
          this.options.sectionHeading,
          logbookRenderer.render(groupedTasks)
        );

        if (didChange) {
          changedDayCount++;
        }
      }

      await this.writeOptions({
        latestSyncTime: moment().unix(),
        dailyStats,
        thingsAccessStatus: fetchResult.accessStatus,
      });

      const repairLookbackDays =
        fetchResult.repairLookbackDays ||
        (fetchResult.source === "applescript"
          ? this.options.appleScriptFallbackLookbackDays
          : this.getReviewWindowDayCount());

      const sourceLabel =
        fetchResult.source === "applescript"
          ? `Things AppleScript, repairing last ${repairLookbackDays} days`
          : `Things SQLite, repairing last ${repairLookbackDays} days`;

      this.syncStatus = {
        isSyncing: false,
        message: `Last result: ${taskCount} tasks, ${changedDayCount}/${dayCount} notes updated via ${sourceLabel}. ${fetchResult.accessStatus.message}`,
      };

      new Notice(
        `Things Toolkit sync complete (${taskCount} tasks, ${changedDayCount} notes updated)`
      );
    } catch (err) {
      console.error("[Things Toolkit] Sync failed", err);

      const errorMessage = err instanceof Error ? err.message : String(err);
      this.syncStatus = {
        isSyncing: false,
        message: `Last result: sync failed. ${errorMessage}`,
      };

      new Notice("Things Toolkit sync failed");
    } finally {
      await this.refreshRecentDailyStats();
      this.updateStatusBar();
      this.refreshReviewViews();
      this.settingsTab?.display();
      this.scheduleNextSync();
    }
  }

  buildDailyStats(
    dayEntries: [string, ITask[]][],
    source: IDailyLogbookStat["source"],
    syncedAt: number
  ): Record<string, IDailyLogbookStat> {
    const moment = getMoment();
    const dailyStats: Record<string, IDailyLogbookStat> = {
      ...(this.options.dailyStats || {}),
    };

    dayEntries.forEach(([dateStr, tasks]) => {
      const dateKey = moment(dateStr).format("YYYY-MM-DD");

      dailyStats[dateKey] = {
        taskCount: tasks.length,
        source,
        syncedAt,
      };
    });

    return dailyStats;
  }

  getTaskCountForDay(dateKey: string): number {
    return this.options.dailyStats?.[dateKey]?.taskCount || 0;
  }

  getReviewWindowDayCount(): number {
    return Math.max(7, Math.floor(Number(this.options.reviewWindowDays) || 365));
  }

  async refreshRecentDailyStats(
    dayCount = this.getReviewWindowDayCount()
  ): Promise<void> {
    const moment = getMoment();
    const dailyStats: Record<string, IDailyLogbookStat> = {
      ...(this.options.dailyStats || {}),
    };
    const dailyNotes = getAllDailyNotes();
    const syncedAt = moment().unix();
    const end = moment().startOf("day");
    const start = end.clone().subtract(dayCount - 1, "days");

    for (
      let date = start.clone();
      date.isSameOrBefore(end);
      date.add(1, "day")
    ) {
      const dateKey = getDateKey(date);
      const dailyNote = getDailyNote(toDailyNoteDate(date), dailyNotes);

      if (!isTFile(dailyNote)) {
        dailyStats[dateKey] = {
          taskCount: 0,
          source: "daily-note",
          syncedAt,
        };
        continue;
      }

      const fileContents = await this.app.vault.read(dailyNote);
      dailyStats[dateKey] = {
        taskCount: countThingsTasksInSection(
          fileContents,
          this.options.sectionHeading
        ),
        source: "daily-note",
        syncedAt,
      };
    }

    await this.writeOptions({ dailyStats });
  }

  getCurrentCompletionStreak(): number {
    const moment = getMoment();
    let streak = 0;

    for (
      let date = moment().startOf("day");
      this.getTaskCountForDay(getDateKey(date)) > 0;
      date = date.clone().subtract(1, "day")
    ) {
      streak++;
    }

    return streak;
  }

  async writeDayReview(
    dateKey: string,
    diff: Partial<IDailyLogbookReview>
  ): Promise<void> {
    const moment = getMoment();
    const dailyReviews: Record<string, IDailyLogbookReview> = {
      ...(this.options.dailyReviews || {}),
    };

    const nextReview: IDailyLogbookReview = {
      ...(dailyReviews[dateKey] || {}),
      ...diff,
      updatedAt: moment().unix(),
    };

    if (!nextReview.rating && !nextReview.reflection) {
      delete dailyReviews[dateKey];
    } else {
      dailyReviews[dateKey] = nextReview;
    }

    await this.writeOptions({ dailyReviews });
    this.refreshReviewViews();
  }

  async openDailyNote(dateKey: string): Promise<void> {
    const moment = getMoment();
    const date = moment(dateKey, "YYYY-MM-DD");
    const dailyNotes = getAllDailyNotes();
    let dailyNote = getDailyNote(toDailyNoteDate(date), dailyNotes);

    if (!dailyNote) {
      dailyNote = await createDailyNote(toDailyNoteDate(date));
    }

    if (!isTFile(dailyNote)) {
      throw new Error("Daily note could not be opened as a file");
    }

    const leaf = this.getDailyNoteOpenLeaf();
    await leaf.openFile(dailyNote, { active: true });
    await this.app.workspace.revealLeaf(leaf);
  }

  private getDailyNoteOpenLeaf(): WorkspaceLeaf {
    const rootLeaf = this.app.workspace.getMostRecentLeaf(
      this.app.workspace.rootSplit
    );

    if (rootLeaf?.view instanceof MarkdownView) {
      return rootLeaf;
    }

    return this.app.workspace.getLeaf("tab");
  }

  refreshReviewViews(): void {
    const leaves: WorkspaceLeaf[] = this.app.workspace.getLeavesOfType(
      VIEW_TYPE_THINGS_TOOLKIT_REVIEW
    );

    leaves.forEach((leaf: WorkspaceLeaf) => {
      const view = leaf.view;

      if (view instanceof ThingsToolkitReviewView) {
        view.display();
      }
    });
  }

  updateStatusBar(): void {
    const moment = getMoment();

    if (!this.statusBarEl) {
      return;
    }

    const todayKey = moment().format("YYYY-MM-DD");
    const todayCount = this.getTaskCountForDay(todayKey);
    const streak = this.getCurrentCompletionStreak();

    this.statusBarEl.setText(`Things: ${todayCount} today | ${streak}d streak`);
    this.statusBarEl.setAttribute("aria-label", "Open Things toolkit review");
  }

  cancelScheduledSync(): void {
    if (this.syncTimeoutId !== undefined) {
      window.clearTimeout(this.syncTimeoutId);
      this.syncTimeoutId = undefined;
    }
  }

  scheduleNextSync(): void {
    const moment = getMoment();
    const now = moment().unix();

    this.cancelScheduledSync();

    if (
      !this.isSyncSupported() ||
      !this.options.isSyncEnabled ||
      !this.options.syncInterval
    ) {
      console.debug("[Things Toolkit] scheduling skipped, no syncInterval set");
      return;
    }

    const { latestSyncTime, syncInterval } = this.options;
    const nextSync = getNextSyncDelayMs(
      latestSyncTime,
      this.lastSyncAttemptTime,
      syncInterval,
      now
    );

    console.debug(`[Things Toolkit] next sync scheduled in ${nextSync}ms`);

    this.syncTimeoutId = window.setTimeout(() => {
      void this.syncLogbook();
    }, nextSync);
  }

  async loadOptions(): Promise<void> {
    const loadedData = (await this.loadData()) as Partial<ISettings> | null;

    this.options = {
      ...DEFAULT_SETTINGS,
      ...(loadedData ?? {}),
    };

    if (!this.options.hasAcceptedDisclaimer) {
      this.options.isSyncEnabled = false;
    }
  }

  async writeOptions(diff: Partial<ISettings>): Promise<void> {
    this.options = Object.assign({}, this.options, diff);

    if (diff.isSyncEnabled !== undefined) {
      if (diff.isSyncEnabled) {
        this.tryToScheduleSync();
      } else {
        this.cancelScheduledSync();
      }
    } else if (diff.syncInterval !== undefined && this.options.isSyncEnabled) {
      this.tryToScheduleSync();
    }

    await this.saveData(this.options);
  }
}

import { App, PluginSettingTab, Setting, moment } from "obsidian";

import type ThingsToolkitPlugin from "./index";
import {
  DEFAULT_APPLESCRIPT_FALLBACK_LOOKBACK_DAYS,
  IThingsAccessStatus,
  MIN_APPLESCRIPT_FALLBACK_LOOKBACK_DAYS,
  ThingsAccessMode,
  ThingsToolkitSource,
} from "./things";
import { getChildProcessModule } from "./nodeUtils";

export const DEFAULT_SECTION_HEADING = "## Things";
export const DEFAULT_SYNC_FREQUENCY_SECONDS = 30 * 60; // Every 30 minutes
export const DEFAULT_REVIEW_WINDOW_DAYS = 365;
export const DEFAULT_TAG_PREFIX = "things/";
export const DEFAULT_CANCELLED_MARK = "c";

export type DayReviewRating = "good" | "steady" | "improve";

export interface IDailyLogbookStat {
  taskCount: number;
  source: ThingsToolkitSource;
  syncedAt: number;
}

export interface IDailyLogbookReview {
  rating?: DayReviewRating;
  reflection?: string;
  updatedAt?: number;
}

export interface ISettings {
  hasAcceptedDisclaimer: boolean;
  latestSyncTime: number;
  appleScriptFallbackLookbackDays: number;
  thingsAccessMode: ThingsAccessMode;
  thingsAccessStatus?: IThingsAccessStatus;
  reviewWindowDays: number;
  dailyStats: Record<string, IDailyLogbookStat>;
  dailyReviews: Record<string, IDailyLogbookReview>;

  doesSyncNoteBody: boolean;
  doesSyncProject: boolean;
  doesAddNewlineBeforeHeadings: boolean;
  isSyncEnabled: boolean;
  sectionHeading: string;
  syncInterval: number;
  tagPrefix: string;
  canceledMark: string;
}

export const DEFAULT_SETTINGS: Readonly<ISettings> = Object.freeze({
  hasAcceptedDisclaimer: false,
  latestSyncTime: 0,
  appleScriptFallbackLookbackDays: DEFAULT_APPLESCRIPT_FALLBACK_LOOKBACK_DAYS,
  thingsAccessMode: "auto",
  thingsAccessStatus: undefined,
  reviewWindowDays: DEFAULT_REVIEW_WINDOW_DAYS,
  dailyStats: {},
  dailyReviews: {},

  doesSyncNoteBody: true,
  doesSyncProject: false,
  doesAddNewlineBeforeHeadings: false,
  isSyncEnabled: false,
  syncInterval: DEFAULT_SYNC_FREQUENCY_SECONDS,
  sectionHeading: DEFAULT_SECTION_HEADING,
  tagPrefix: DEFAULT_TAG_PREFIX,
  canceledMark: DEFAULT_CANCELLED_MARK,
});

export class ThingsToolkitSettingsTab extends PluginSettingTab {
  private readonly toolkitPlugin: ThingsToolkitPlugin;

  constructor(app: App, plugin: ThingsToolkitPlugin) {
    super(app, plugin);
    this.toolkitPlugin = plugin;
  }

  display(): void {
    this.containerEl.empty();

    new Setting(this.containerEl).setName("Sync Engine").setHeading();
    if (this.toolkitPlugin.isSyncSupported()) {
      this.addResetLastSyncSetting();
      this.addThingsAccessModeSetting();
      this.addThingsAccessStatusSetting();
      this.addSyncEnabledSetting();
      this.addSyncIntervalSetting();
      this.addAppleScriptFallbackLookbackSetting();
    } else {
      this.addUnsupportedSyncSetting();
    }

    new Setting(this.containerEl).setName("Daily Notes").setHeading();
    this.addSectionHeadingSetting();
    this.addDoesSyncNoteBodySetting();
    this.addDoesSyncProjectSetting();
    this.addDoesAddNewlineBeforeHeadingsSetting();

    new Setting(this.containerEl).setName("Imported Tags").setHeading();
    this.addTagPrefixSetting();
    this.addCanceledMarkSetting();

    new Setting(this.containerEl).setName("Review Calendar").setHeading();
    this.addReviewWindowDaysSetting();
  }

  addSectionHeadingSetting(): void {
    new Setting(this.containerEl)
      .setName("Section heading")
      .setDesc(
        "Markdown heading to replace or append when adding Things items to a daily note"
      )
      .addText((textfield) => {
        textfield.setValue(this.toolkitPlugin.options.sectionHeading);
        textfield.onChange((rawSectionHeading) => {
          const sectionHeading = this.normalizeSectionHeading(rawSectionHeading);
          void this.toolkitPlugin.writeOptions({ sectionHeading });
        });
      });
  }

  addReviewWindowDaysSetting(): void {
    new Setting(this.containerEl)
      .setName("Review window")
      .setDesc("Number of recent days to show and repair in the review calendar")
      .addText((textfield) => {
        textfield.setValue(String(this.toolkitPlugin.options.reviewWindowDays));
        textfield.inputEl.type = "number";
        textfield.inputEl.onblur = (event: FocusEvent) => {
          const target = event.target;
          if (!(target instanceof HTMLInputElement)) {
            return;
          }

          const reviewWindowDays = Math.max(
            30,
            Math.floor(Number(target.value) || DEFAULT_REVIEW_WINDOW_DAYS)
          );

          textfield.setValue(String(reviewWindowDays));
          void this.toolkitPlugin.writeOptions({ reviewWindowDays });
        };
      });
  }

  normalizeSectionHeading(rawSectionHeading: string): string {
    const sectionHeading = rawSectionHeading.trim();

    if (!sectionHeading) {
      return DEFAULT_SECTION_HEADING;
    }

    if (/^#{1,6}\s+\S/.test(sectionHeading)) {
      return sectionHeading;
    }

    return `## ${sectionHeading.replace(/^#+\s*/, "")}`;
  }

  addSyncEnabledSetting(): void {
    new Setting(this.containerEl)
      .setName("Enable periodic syncing")
      .addToggle((toggle) => {
        toggle.setValue(this.toolkitPlugin.options.isSyncEnabled);
        toggle.onChange((isSyncEnabled) => {
          void this.toolkitPlugin.writeOptions({ isSyncEnabled });
        });
      });
  }

  addUnsupportedSyncSetting(): void {
    new Setting(this.containerEl)
      .setName("Sync unavailable")
      .setDesc(
        "Things sync runs only in Obsidian for macOS. The plugin can stay enabled here so Obsidian Sync does not disable it on your Mac."
      );
  }

  addThingsAccessModeSetting(): void {
    new Setting(this.containerEl)
      .setName("Things access")
      .setDesc(
        "Auto tries the Things database first, then uses AppleScript when macOS privacy blocks direct access."
      )
      .addDropdown((dropdown) => {
        dropdown
          .addOption("auto", "Auto")
          .addOption("applescript", "AppleScript")
          .addOption("sqlite", "SQLite only");

        dropdown.setValue(this.toolkitPlugin.options.thingsAccessMode);
        dropdown.onChange(async (value: string) => {
          const thingsAccessMode = value as ThingsAccessMode;
          await this.toolkitPlugin.writeOptions({ thingsAccessMode });
          this.display();
        });
      });
  }

  addThingsAccessStatusSetting(): void {
    const accessStatus = this.toolkitPlugin.options.thingsAccessStatus;
    const statusText = accessStatus
      ? `${accessStatus.message} Checked ${moment
          .unix(accessStatus.updatedAt)
          .fromNow()}.`
      : "Not checked yet. Run Sync now to test Things access.";

    new Setting(this.containerEl)
      .setName("macOS privacy status")
      .setDesc(statusText)
      .addButton((button) => {
        button.setButtonText("Full Disk Access");
        button.onClick(() => {
          this.openSystemSettings(
            "x-apple.systempreferences:com.apple.preference.security?Privacy_AllFiles"
          );
        });
      })
      .addButton((button) => {
        button.setButtonText("Automation");
        button.onClick(() => {
          this.openSystemSettings(
            "x-apple.systempreferences:com.apple.preference.security?Privacy_Automation"
          );
        });
      });
  }

  openSystemSettings(url: string): void {
    getChildProcessModule().spawn("open", [url]);
  }

  addDoesSyncNoteBodySetting(): void {
    new Setting(this.containerEl)
      .setName("Include notes")
      .setDesc("Includes MD notes of a task into the synced Obsidian document")
      .addToggle((toggle) => {
        toggle.setValue(this.toolkitPlugin.options.doesSyncNoteBody);
        toggle.onChange((doesSyncNoteBody) => {
          void this.toolkitPlugin.writeOptions({ doesSyncNoteBody });
        });
      });
  }

  addDoesSyncProjectSetting(): void {
    new Setting(this.containerEl)
      .setName("Include project")
      .setDesc(
        "If the Things task belongs to a project, use project name as header instead of area"
      )
      .addToggle((toggle) => {
        toggle.setValue(this.toolkitPlugin.options.doesSyncProject);
        toggle.onChange((doesSyncProject) => {
          void this.toolkitPlugin.writeOptions({ doesSyncProject });
        });
      });
  }

  addSyncIntervalSetting(): void {
    new Setting(this.containerEl)
      .setName("Sync frequency")
      .setDesc("Number of seconds the plugin will wait before syncing again")
      .addText((textfield) => {
        textfield.setValue(String(this.toolkitPlugin.options.syncInterval));
        textfield.inputEl.type = "number";
        textfield.inputEl.onblur = (event: FocusEvent) => {
          const target = event.target;
          if (!(target instanceof HTMLInputElement)) {
            return;
          }

          const syncInterval = Math.max(
            60,
            Math.floor(Number(target.value) || DEFAULT_SYNC_FREQUENCY_SECONDS)
          );

          textfield.setValue(String(syncInterval));
          void this.toolkitPlugin.writeOptions({ syncInterval });
        };
      });
  }

  addAppleScriptFallbackLookbackSetting(): void {
    new Setting(this.containerEl)
      .setName("AppleScript fallback lookback")
      .setDesc(
        `Days to repair when macOS blocks direct Things database access. The recent review window always uses at least ${MIN_APPLESCRIPT_FALLBACK_LOOKBACK_DAYS} days.`
      )
      .addText((textfield) => {
        textfield.setValue(
          String(this.toolkitPlugin.options.appleScriptFallbackLookbackDays)
        );
        textfield.inputEl.type = "number";
        textfield.inputEl.onblur = (event: FocusEvent) => {
          const target = event.target;
          if (!(target instanceof HTMLInputElement)) {
            return;
          }

          const appleScriptFallbackLookbackDays = Math.max(
            1,
            Math.floor(
              Number(target.value) || DEFAULT_APPLESCRIPT_FALLBACK_LOOKBACK_DAYS
            )
          );

          textfield.setValue(String(appleScriptFallbackLookbackDays));
          void this.toolkitPlugin.writeOptions({
            appleScriptFallbackLookbackDays,
          });
        };
      });
  }

  addTagPrefixSetting(): void {
    new Setting(this.containerEl)
      .setName("Tag prefix")
      .setDesc(
        "Prefix added to Things tags when imported into Obsidian (e.g. #things/work)"
      )
      .addText((textfield) => {
        textfield.setValue(this.toolkitPlugin.options.tagPrefix);
        textfield.onChange((tagPrefix) => {
          void this.toolkitPlugin.writeOptions({ tagPrefix });
        });
      });
  }

  addCanceledMarkSetting(): void {
    new Setting(this.containerEl)
      .setName("Canceled mark")
      .setDesc("Mark character to use for canceled tasks")
      .addText((textfield) => {
        textfield.setValue(this.toolkitPlugin.options.canceledMark);
        textfield.onChange((canceledMark) => {
          void this.toolkitPlugin.writeOptions({ canceledMark });
        });
      });
  }

  addDoesAddNewlineBeforeHeadingsSetting(): void {
    new Setting(this.containerEl)
      .setName("Empty line before headings")
      .setDesc(
        "When grouping tasks with headings by area or project, add an empty line before that heading"
      )
      .addToggle((toggle) => {
        toggle.setValue(
          this.toolkitPlugin.options.doesAddNewlineBeforeHeadings
        );
        toggle.onChange((doesAddNewlineBeforeHeadings) => {
          void this.toolkitPlugin.writeOptions({
            doesAddNewlineBeforeHeadings,
          });
        });
      });
  }

  addResetLastSyncSetting(): void {
    const { latestSyncTime } = this.toolkitPlugin.options;
    const { syncStatus } = this.toolkitPlugin;
    const syncTime =
      latestSyncTime > 0
        ? moment.unix(this.toolkitPlugin.options.latestSyncTime).fromNow()
        : "Never";

    new Setting(this.containerEl)
      .setDesc(
        createFragment((el) => {
          el.appendText("Last sync: ");
          el.createSpan({ cls: "u-pop", text: syncTime });

          if (syncStatus.message) {
            el.createEl("br");
            el.appendText(syncStatus.message);
          }
        })
      )
      .addButton((button) => {
        button.setButtonText(syncStatus.isSyncing ? "Syncing..." : "Sync now");
        button.setClass("mod-cta");
        button.setDisabled(syncStatus.isSyncing);
        button.onClick(async () => {
          button.setDisabled(true);
          await this.toolkitPlugin.tryToSyncLogbook();
          this.display();
        });
      })
      .addButton((button) => {
        button.setButtonText("Reset sync history");
        button.setClass("mod-danger");
        button.setDisabled(syncStatus.isSyncing);
        button.onClick(() => {
          void this.toolkitPlugin.writeOptions({ latestSyncTime: 0 });
          this.display();
        });
      })
      .addExtraButton((component) => {
        component.setIcon("lucide-info");
        component.setTooltip(
          "Resetting sync history will rewrite the configured Things section in matching daily notes."
        );
      });
  }
}
